<template><section class="container"><h2>互动排行</h2><div class="page-actions"><select v-model="limit" @change="load"><option :value="10">10</option><option :value="20">20</option><option :value="50">50</option></select></div><div v-if="loading" class="loading"/><div v-else-if="error" class="error">{{error}}</div><table v-else class="admin-table"><tr><th>articleId</th><th>title</th><th>categoryName</th><th>view</th><th>like</th><th>comment</th><th>share</th><th>score</th></tr><tr v-for="i in items" :key="i.articleId"><td>{{i.articleId}}</td><td>{{i.title}}</td><td>{{i.categoryName}}</td><td>{{i.viewCount}}</td><td>{{i.likeCount}}</td><td>{{i.commentCount}}</td><td>{{i.shareCount}}</td><td>{{i.totalScore}}</td></tr></table></section></template>
<script setup>import { onMounted, ref } from 'vue'; import { getInteractions } from '../../api/admin'; const loading=ref(false); const error=ref(''); const items=ref([]); const limit=ref(10); const load=async()=>{loading.value=true; try{items.value=await getInteractions({limit:limit.value})}catch(e){error.value=e.message}finally{loading.value=false}}; onMounted(load)</script>
